#include <iostream>
using namespace std;
int a[10]={6,2,5,5,4,5,6,3,7,6};
int func(int x)
{
    int count=0;
    if(x/10==0)
    {
        return a[x];
    }
    return func(x/10)+func(x%10);
}
int main()
{
    int count=0,n;
    cin>>n;
    for(int a=0;a<=1111;a++)
    {
        for(int b=0;b<=1111;b++)
        {
            int c=a+b;
            if(func(a)+func(b)+func(c)==n-4)
            {
                count++;
            }
        }
    }
    cout<<count;
    return 0;
}
